import { Card, Typography } from 'antd';

const { Text } = Typography;
const { Meta } = Card;

export const ProjectOverviewContainer = () => {
  const ProjectCard = ({ alt, src, title, description }) => (
    <Card
      hoverable
      style={{ width: 240, marginBottom: '20px'}}
      cover={
        <img
          draggable={false}
          alt={alt}
          src={src}
        />
      }
    >
      <Meta title={title} description={description} />
    </Card>
  )

  return (
    <div>
      <Text>Here you can get an overview of my projects.</Text>
      <div className='ProjectGrid'>
        <ProjectCard alt="Project 1" src="https://os.alipayobjects.com/rmsportal/QBnOOoLaAfKPirc.png" title="Project One" description="Description for project one" />
        <ProjectCard alt="Project 2" src="https://os.alipayobjects.com/rmsportal/QBnOOoLaAfKPirc.png" title="Project Two" description="Description for project two" />
        <ProjectCard alt="Project 3" src="https://os.alipayobjects.com/rmsportal/QBnOOoLaAfKPirc.png" title="Project Three" description="Description for project three" />
        <ProjectCard alt="Project 4" src="https://os.alipayobjects.com/rmsportal/QBnOOoLaAfKPirc.png" title="Project Four" description="Description for project four" />
        <ProjectCard alt="Project 5" src="https://os.alipayobjects.com/rmsportal/QBnOOoLaAfKPirc.png" title="Project Five" description="Description for project five" />
      </div>
    </div>
  );
}
